// Expand offense into (provider x target) work items.
// Defensively resolve inputs from top-level $json OR a nested passthrough object,
// since n8n 1.x executeWorkflowTrigger may deliver fields at either level depending
// on the caller's mappingMode and the trigger's typeVersion.
const raw = $input.first().json;
const input = (raw.case_id !== undefined || raw.indicator !== undefined)
  ? raw
  : (raw.body || raw.data || raw.input || raw);
const caseId = input.case_id;

function isPublicIp(ip) {
  if (!ip || ip === 'unknown') return false;
  const m = ip.match(/^(\d+)\.(\d+)\.(\d+)\.(\d+)$/);
  if (!m) return false;
  const o = m.slice(1).map(Number);
  if (o.some(x => x > 255)) return false;
  if (o[0] === 10) return false;
  if (o[0] === 127) return false;
  if (o[0] === 169 && o[1] === 254) return false;
  if (o[0] === 172 && o[1] >= 16 && o[1] <= 31) return false;
  if (o[0] === 192 && o[1] === 168) return false;
  if (o[0] === 0) return false;
  return true;
}

const PROVIDERS_BY_TYPE = {
  ip: ['abuseipdb', 'shodan', 'otx'],
  domain: ['otx'],
  url: ['otx'],
  hash: ['otx']
};

// Collect unique targets
const targets = [];
const seen = new Set();
function addTarget(value, type) {
  if (!value || value === 'unknown') return;
  const k = type + ':' + value;
  if (seen.has(k)) return;
  seen.add(k);
  targets.push({ value, type });
}

const itype = (input.indicator_type || '').toLowerCase();
const normType = ['ip','ipv4','ip-src'].includes(itype) ? 'ip'
  : ['domain','hostname'].includes(itype) ? 'domain'
  : ['url'].includes(itype) ? 'url'
  : ['hash','md5','sha1','sha256','file'].includes(itype) ? 'hash'
  : null;
if (normType) addTarget(input.indicator, normType);
if (isPublicIp(input.source_ip)) addTarget(input.source_ip, 'ip');

// Fan out to provider work items
const items = [];
for (const t of targets) {
  const providers = PROVIDERS_BY_TYPE[t.type] || [];
  for (const provider of providers) {
    items.push({
      json: {
        case_id: caseId,
        target_value: t.value,
        target_type: t.type,
        provider,
        cache_key: `enrich:${provider}:${t.type}:${t.value}`
      }
    });
  }
}

// If nothing to enrich, emit a single sentinel so downstream note step can still run
if (items.length === 0) {
  return [{ json: { case_id: caseId, target_value: null, target_type: null, provider: null, cache_key: null, _empty: true } }];
}
return items;

return $input.all().map(item => {
  const j = item.json;
  let result = null;
  try { result = JSON.parse(j.cached_raw); } catch (e) { result = { provider: j.provider, ok: false, data: null }; }
  return { json: { case_id: j.case_id, target_value: j.target_value, target_type: j.target_type, provider: j.provider, result } };
});

// Normalize whichever provider produced this item. Best-effort: HTTP errors
// arrive as items with an `error` field or non-2xx; mark ok=false.
return $input.all().map(item => {
  const j = item.json;
  const provider = j.provider;
  const base = { case_id: j.case_id, target_value: j.target_value, target_type: j.target_type, provider };
  // n8n continueRegularOutput puts failures in j.error or leaves body empty
  const failed = j.error !== undefined || j.statusCode >= 500 || (j.body && j.body.error);
  let data = null, ok = false;
  try {
    if (provider === 'abuseipdb' && j.data) { data = { confidence: j.data.abuseConfidenceScore, reports: j.data.totalReports, country: j.data.countryCode }; ok = true; }
    else if (provider === 'shodan') {
      if (j.ports || j.data || j.vulns) { data = { ports: j.ports || [], vulns: Object.keys(j.vulns || {}), org: j.org || null }; ok = true; }
      else if (j.statusCode === 404 || (j.error && String(j.error).includes('404'))) { data = { ports: [], vulns: [], org: null, note: 'no shodan info' }; ok = true; }
    }
    else if (provider === 'otx' && j.pulse_info) { data = { pulses: j.pulse_info.count || 0, top: (j.pulse_info.pulses || []).slice(0,3).map(p => p.name) }; ok = true; }
  } catch (e) { ok = false; }
  if (failed && !ok) ok = false;
  return { json: { ...base, result: { provider, ok, data: ok ? data : null } } };
});

// Single aggregation point. Fires once: via Normalize Result on the provider
// path, or via Has Targets? on the empty path. Pull fresh + cached results by
// node reference so a mixed cache-hit/miss run still yields ONE verdict set.
function safeAll(name){ try { return $(name).all().map(i => i.json); } catch(e){ return []; } }
const fresh = safeAll('Normalize Result');
const cached = safeAll('Decode Cache Hit');
const items = [...fresh, ...cached].filter(j => j && j.target_value);

let caseId = null;
try { caseId = $('Build Targets').first().json.case_id; } catch(e){}
if (items.length) caseId = items[0].case_id || caseId;
if (items.length === 0) return [{ json: { case_id: caseId, verdicts: [] } }];

const byTarget = {};
for (const it of items) {
  const key = it.target_type + ':' + it.target_value;
  if (!byTarget[key]) byTarget[key] = { value: it.target_value, type: it.target_type, sources: {}, unavailable: [] };
  const r = it.result || { provider: it.provider, ok: false, data: null };
  if (r.ok && r.data) byTarget[key].sources[r.provider] = r.data;
  else if (r.provider) byTarget[key].unavailable.push(r.provider);
}
const verdicts = Object.values(byTarget).map(v => {
  const parts = [];
  if (v.sources.abuseipdb) parts.push(`AbuseIPDB ${v.sources.abuseipdb.confidence}%`);
  if (v.sources.otx) parts.push(`OTX ${v.sources.otx.pulses} pulses`);
  if (v.sources.shodan) parts.push(`Shodan ${(v.sources.shodan.ports||[]).length} ports`);
  v.summary = parts.length ? parts.join(' \u00b7 ') : 'no provider data';
  return v;
});
return [{ json: { case_id: caseId, verdicts } }];

// Build one note payload + N ioc payloads from verdicts.
const { case_id, verdicts } = $input.first().json;
// IRIS v2.4.20 verified type ids; hash chosen by value length
function iocTypeId(v) {
  if (v.type === 'ip') return 79;       // ip-src
  if (v.type === 'domain') return 20;   // domain
  if (v.type === 'url') return 141;     // url
  if (v.type === 'hash') { const L = (v.value || '').length; return L === 64 ? 113 : L === 40 ? 111 : 90; } // sha256/sha1/md5
  return 90;
}

if (!verdicts || verdicts.length === 0) {
  return [{ json: { case_id, note: { note_title: 'Automated enrichment', note_content: 'No external indicators to enrich for this offense.' }, iocs: [] } }];
}

let md = '## Automated threat-intel enrichment\n\n';
for (const v of verdicts) {
  md += `### ${v.type.toUpperCase()} \`${v.value}\`\n\n`;
  md += `**Summary:** ${v.summary}\n\n`;
  md += '| Provider | Finding |\n|---|---|\n';
  if (v.sources.abuseipdb) md += `| AbuseIPDB | confidence ${v.sources.abuseipdb.confidence}%, ${v.sources.abuseipdb.reports} reports (${v.sources.abuseipdb.country||'?'}) |\n`;
  if (v.sources.shodan) md += `| Shodan | ports ${(v.sources.shodan.ports||[]).join(', ')||'none'}; vulns ${(v.sources.shodan.vulns||[]).join(', ')||'none'} |\n`;
  if (v.sources.otx) md += `| OTX | ${v.sources.otx.pulses} pulses${v.sources.otx.top&&v.sources.otx.top.length?': '+v.sources.otx.top.join('; '):''} |\n`;
  for (const u of (v.unavailable||[])) md += `| ${u} | unavailable |\n`;
  md += '\n';
}

const iocs = verdicts.map(v => ({
  ioc_type_id: iocTypeId(v),
  ioc_value: v.value,
  ioc_description: `SIEM enrichment: ${v.summary}`,
  ioc_tags: 'siem,enrichment',
  ioc_tlp_id: 2
}));

return [{ json: { case_id, note: { note_title: 'Automated enrichment', note_content: md }, iocs } }];

// n8n 2.x Redis 'get' returns only `cached_raw` and drops the input fields.
// Re-attach the original work-item fields from Build Targets by index
// (Cache Get preserves item order 1:1), keeping cached_raw.
const src = $('Build Targets').all();
return $input.all().map((item, idx) => ({
  json: { ...(src[idx] ? src[idx].json : {}), cached_raw: item.json.cached_raw },
}));

// Re-attach work-item context lost when the AbuseIPDB HTTP node replaced
// the item with the API response. Merge by index from Filter AbuseIPDB; the
// response fields are spread on top so Normalize Result reads both.
const ctx = $('Filter AbuseIPDB').all();
return $input.all().map((it, i) => ({
  json: { ...(ctx[i] ? ctx[i].json : {}), ...it.json },
}));

// Re-attach work-item context lost when the Shodan HTTP node replaced
// the item with the API response. Merge by index from Filter Shodan; the
// response fields are spread on top so Normalize Result reads both.
const ctx = $('Filter Shodan').all();
return $input.all().map((it, i) => ({
  json: { ...(ctx[i] ? ctx[i].json : {}), ...it.json },
}));

// Re-attach work-item context lost when the OTX HTTP node replaced
// the item with the API response. Merge by index from Filter OTX; the
// response fields are spread on top so Normalize Result reads both.
const ctx = $('Filter OTX').all();
return $input.all().map((it, i) => ({
  json: { ...(ctx[i] ? ctx[i].json : {}), ...it.json },
}));
